async (params, browser) => {
  // Open Notion page
  await browser.open(`${params.page_url}`)

  // Wait for page content
  await browser.waitForSelector('.notion-page-content, .notion-scroller, [data-content-editable-root]', 15000)

  // Let page fully render
  await browser.wait(3000)

  // Extract page content from DOM
  const result = await browser.evaluate(`const title = document.querySelector('.notion-page__title, [placeholder="Untitled"], .notranslate[data-content-editable-leaf]')?.textContent?.trim() || ''; const blocks = []; const contentEls = document.querySelectorAll('.notion-page-content [data-block-id], .notion-scroller .notion-selectable'); for (let i = 0; i < Math.min(contentEls.length, 50); i++) { const el = contentEls[i]; const text = el.textContent?.trim() || ''; if (text) blocks.push({ type: el.getAttribute('data-block-type') || el.className.match(/notion-(\w+)-block/)?.[1] || 'text', content: text.substring(0, 300) }); } const properties = []; const propEls = document.querySelectorAll('.notion-collection-page-properties .notion-collection_view-block [data-block-id]'); propEls.forEach(p => { const label = p.querySelector('.notion-collection-property-title')?.textContent?.trim() || ''; const value = p.querySelector('.notion-collection-property-value, .notion-property-value')?.textContent?.trim() || ''; if (label || value) properties.push({ label, value }); }); return { title: title, block_count: blocks.length, blocks: blocks, properties: properties, url: window.location.href }`)

  return result
}
